exercises.solution_code:
#include <algorithm>
#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    std::sort(v.begin(), v.end(),
        [](int a, int b)
        {
            auto absA{ a < 0 ? -a : a };
            auto absB{ b < 0 ? -b : b };
            if (absA != absB)
                return absA < absB;
            return a < b;
        });

    for (int i{ 0 }; i < n; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << v[i];
    }
    std::cout << '\n';

    return 0;
}
